		_html += "      <tr>";
		_html += "         <td width='70%'>";
		_html += "            <input id='detail_search' name='detail_search' type='text' class='form-control detail_search' placeholder='Buscar' aria-label='Buscar'>";
		_html += "         </td>";
		_html += "         <td width='30%'>";
		_html += "            <button data-target='" + _target + "' class='btn btn-secondary btn-sm btn-search-details' type='button'><i class='material-icons' style='font-size:22px;vertical-align:middle;'>search</i>Buscar</button>";
		_html += "         </td>";
		_html += "      </tr>";
		_html += "   </table>";
		_html += "<div id='" + _id + "' class='container-full " + _id + "'></div>";
