	onPageDetails: function (_target, _page) {
		var _search = $(".detail_search").val();
		var _type = _target.replace('.', '');
		var _id = ("areaDetails" + _type);
		var _html = "<span class='badge badge-danger'>Sin datos para la consulta</span>";
		_FUNCTIONS._jsonLastFilter["extension"] = _target;
		_FUNCTIONS._jsonLastFilter["page"] = _page;
		_FUNCTIONS._jsonLastFilter["pagesize"] = 25;
		_FUNCTIONS._jsonLastFilter["where"] = "";
		if (_search != "") { _FUNCTIONS._jsonLastFilter["where"] = ("filename LIKE '%" + _search + "%'"); }
		_AJAX._waiter = true;
		_AJAX.UiTransfersDetails(_FUNCTIONS._jsonLastFilter).then(function (data) {
			var _color = "";
			var _bData = false;
			console.log(data);
			$.each(data.data, function (i, item) {
				_bData = true;
				if (i == 0) {
					var _image = "file.png";
					switch (item.extension) {
						case ".pdf":
							_image = "pdf.png";
							break;
						case ".tiff":
						case ".tif":
							_image = "tif.png";
							break;
					}
					_html = "<a href='#' class='btn btn-sm btn-raised btn-success btn-export-excel' data-tab='detalles'>Exportar a Excel</a>";
					_html += "<table class='table table-sm table-borderless' style='font-size:0.8rem;width:100%;'>";
					_html += "	<thead class='thead-dark'>";
					_html += "		<tr>";
					_html += "			<th><img src='./assets/img/" + _image + "' style='width:24px;'/></th>";
					_html += "			<th>Creado el</th>";
					_html += "			<th>Archivo</th>";
					_html += "			<th>Páginas</th>";
					_html += "			<th>Carpeta</th>";
					_html += "			<th>Estado</th>";
					_html += "			<th>SLA</th>";
					_html += "			<th>T.proc.</th>";
					_html += "		</tr>";
					_html += "	</thead>";
					_html += "	<tbody>";
				}
				_html += "	<tr>";
				_html += "		<td>#" + item.id + "</td>";
				_html += "		<td>" + _TOOLS.formatDDMMYYYYHHMM(item.created, "/") + "</td>";
				var _iTTLDiff = _TOOLS.diffSeconds(_TOOLS.getNowYYYYMMDD(), item.created);
				_iTTLDiff = (_iTTLDiff / 60 / 60);
				_color = "primary";
				_color_file = "secondary";
				//if (_iTTLDiff > item.ttl_storage) {_color = "secondary";}

				var _filename = item.filename.substring(item.filename.lastIndexOf('/') + 1);
				var pattern = /^((http|https|ftp):\/\/)/;
				if (pattern.test(item.filename)) {
					_filename = "<a style='color:white;' href='" + item.filename + "' target='_blank'><i style='font-size:14px;' class='material-icons'>save</i> " + _filename + "</a>";
					_color_file = "info";
				}

				_html += "   	<td data-filename='" + item.filename + "'><span style='font-size:0.75rem;' class='badge badge-" + _color_file + "'>" + _filename + "</span></td>";
				_html += "		<td>" + item.pages + "</td>";
				_html += "		<td>" + item.filepath.split('\\').pop() + "</td>";
				var _status = "N/A";
				var _iDiff = "";
				item.sla = (item.sla * 60);
				$.each(item.status, function (x, o) {
					if (x == 0) {
						_status = "<div><b>" + o.status + "</b> " + o.created + "</div>";
						_iDiff = _TOOLS.diffSeconds(o.created, item.created);
						_iDiff = (_iDiff / 60);
						_color = "success";
						if (_iDiff > (item.sla / 2)) { _color = "info"; }
						if (_iDiff > item.sla) { _color = "danger"; }
						var _dtm = _TOOLS.toHoursAndMinutes(_iDiff)
						var _te = (_dtm.hours + ":" + _dtm.minutes);
						_iDiff = "<span style='font-size:0.75rem;' class='badge badge-" + _color + "'>" + _te + " Hs.</span>";
					}
				});
				_html += "		<td>" + _status + "</td>";
				_html += "		<td>" + (item.sla/60) + "Hs.</td>";
				_html += "		<td>" + _iDiff + "</td>";
				_html += "  </tr>";
			});
			if (_bData) {
				_html += "	</tbody>";
				_html += "</table>";
				_html += "<div class='p-2'>";
				_html += "	<ul class='pagination justify-content-end'>";
				var _totalpages = parseInt(data["totalpages"]);
				var _page = parseInt(data["page"]);
				var _limit = (_page + 10);
				if (_limit > _totalpages) { _limit = _totalpages; }
				if (_totalpages >= 1) {
					if (_page > 1) { _html += "<li class='page-item'><a class='page-link btn-pager' href='#' tabindex='-1' data-target='" + _target + "' data-page='" + (_page - 1) + "'>Previas</a></li>"; }
					for (_i = _page; _i <= _limit; _i++) {
						var _class = "";
						if (_i == _page) { _class = "active"; }
						_html += "<li class='page-item " + _class + "'><a data-target='" + _target + "' data-page='" + _i + "' class='page-link btn-pager' href='#'>" + _i + "</a></li>";
					}
					if ((_limit + 1) <= _totalpages) { _html += "<li class='page-item'><a class='page-link btn-pager' href='#' data-target='" + _target + "' data-page='" + (_limit + 1) + "'>Próximas</a></li>"; }
				}
				_html += "	</ul>";
				_html += "</div>";
			}
			$("." + _id).html(_html);
			$(".tbl-search-detail").removeClass("d-none");
		});
	},
	onPageDetailsExcel: function (_this) {
		if (!confirm("Este proceso puede demorar varios minutos.\nPor favor no cierre el navegador.\n ¿Confirma?")) { return false; }
		_FUNCTIONS._jsonLastFilter["extension"] = "";
		_FUNCTIONS._jsonLastFilter["page"] = -1;
		_FUNCTIONS._jsonLastFilter["pagesize"] = -1;
		_FUNCTIONS._jsonLastFilter["tab"] = _this.attr("data-tab");
		_AJAX.UiTransfersDetailsExcel(_FUNCTIONS._jsonLastFilter).then(function (data) {
			window.open(data.data, '_blank', '');
		}).catch(function (err) {
			console.log(err);
		});
	},
	onCSVManual: function (_this) {
		$(".btn-csv-manual").addClass("d-none");
		var _generated = parseInt(_this.attr("data-exec"));
		if (_generated != 0) {
			if (!confirm("Ya se han procesado CSV el día de hoy. Si acepta se procesarán las fallas de transmisión, en caso de existir.")) {
				$(".btn-csv-manual").removeClass("d-none");
				return false;
			}
		}
		if (!confirm("¿Realmente desea generar los CSV para el intervalo de fechas seleccionado?")) {
			$(".btn-csv-manual").removeClass("d-none");
			return false;
		}
		var _params = {
			"id_client": parseInt($(".cbo_id_client").val()),
			"date_from": $(".browser_date_from").val(),
			"date_to": $(".browser_date_to").val(),
			"generated": _generated
		}
		$.blockUI({ message: '<img src="' + _AJAX._pre + './assets/img/wait.gif" />', css: { border: 'none', backgroundColor: 'transparent', opacity: 1, color: 'transparent' } });
		_AJAX.UiGenerarCSVManual(_params).then(function (data) {
			alert("Se han generado los CSV " + data.post_proc + " / " + data.post_resp + " / " + data.post_stat + ".  Se recargará la página actual.");
			$.unblockUI();
			$(".btn-csv-manual").removeClass("d-none");
			$(".btn-counters").click();
		});
	},
